package com.example.bankingapp;

import android.os.Bundle;
import android.widget.TextView;
import androidx.appcompat.app.AppCompatActivity;
import java.util.HashMap;
import java.util.Map;

public class BankingActivity extends AppCompatActivity {

    private Map<String, Double> accounts;
    private TextView balanceTextView;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_banking);

        balanceTextView = findViewById(R.id.balanceTextView);
        accounts = new HashMap<>();
        accounts.put("user123", 1000.00);

        displayBalance("user123");
    }

    private void displayBalance(String accountId) {
        Double balance = accounts.get(accountId);
        if (balance != null) {
            balanceTextView.setText("Balance: $" + balance);
        } else {
            balanceTextView.setText("Account not found");
        }
    }

    public boolean processTransaction(String accountId, double amount) {
        Double currentBalance = accounts.get(accountId);
        if (currentBalance != null && currentBalance + amount >= 0) {
            accounts.put(accountId, currentBalance + amount);
            displayBalance(accountId);
            return true;
        }
        return false;
    }
}